<?php
namespace App\Controllers; use App\Models\User;
class UserController { public function index(){\render('users/index',['users'=>(new User)->all()]);} public function create(){\render('users/create',['roles'=>(new User)->roles()]);} public function store(){\verify_csrf(); $m=new User; if($m->findByEmail($_POST['email'])){\flash('error','El email ya existe.');\redirect('/users/create');} $m->save(['name'=>trim($_POST['name']),'email'=>trim($_POST['email']),'password_hash'=>password_hash($_POST['password'],PASSWORD_DEFAULT),'role_id'=>$_POST['role_id'],'status'=>$_POST['status']]); \redirect('/users');} public function edit($id){$m=new User;\render('users/edit',['user'=>$m->find($id),'roles'=>$m->roles()]);} public function update($id){\verify_csrf(); $d=['name'=>trim($_POST['name']),'email'=>trim($_POST['email']),'role_id'=>$_POST['role_id'],'status'=>$_POST['status']]; if(!empty($_POST['password']))$d['password_hash']=password_hash($_POST['password'],PASSWORD_DEFAULT); (new User)->save($d,$id); \redirect('/users');}}
